import{_ as s,o as i,c as a,a2 as n}from"./chunks/framework.YhErEiPK.js";const g=JSON.parse('{"title":"How Can I Debug the Mapping, Request, or Response Being Sent by WireMock?","description":"","frontmatter":{},"headers":[],"relativePath":"howto/debug-wiremock.md","filePath":"howto/debug-wiremock.md"}'),t={name:"howto/debug-wiremock.md"};function o(p,e,l,r,c,h){return i(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="how-can-i-debug-the-mapping-request-or-response-being-sent-by-wiremock" tabindex="-1">How Can I Debug the Mapping, Request, or Response Being Sent by WireMock? <a class="header-anchor" href="#how-can-i-debug-the-mapping-request-or-response-being-sent-by-wiremock" aria-label="Permalink to &quot;How Can I Debug the Mapping, Request, or Response Being Sent by WireMock?&quot;">​</a></h1><p>Starting from version <code>1.2.0</code>, we set WireMock logging to <code>info</code> and set the WireMock notifier to being verbose. Now you can exactly know what request was received by the WireMock server and which matching response definition was picked.</p><p>To turn off this feature, set WireMock logging to <code>ERROR</code> in your <code>application.properties</code>:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">logging.level.com.github.tomakehurst.wiremock</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=ERROR</span></span></code></pre></div><p>Or in <code>application.yml</code>:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">logging</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    com.github.tomakehurst.wiremock</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ERROR</span></span></code></pre></div><p>When verbose logging is enabled, you will see output similar to the following in your logs:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2021-01-01 12:00:00.000  INFO --- [qtp123-45] WireMock : Request received:</span></span>
<span class="line"><span>                                      ...</span></span>
<span class="line"><span>                                      Matched response definition:</span></span>
<span class="line"><span>                                      ...</span></span></code></pre></div><p>This detailed logging helps you understand exactly what is being matched and what response is being returned, which is particularly useful when troubleshooting stubbing issues.</p>`,9)])])}const k=s(t,[["render",o]]);export{g as __pageData,k as default};
